  function getDropEconomyValue(path, fallback) {
    if (getEngineLootHelper('getDropEconomyValue')) {
      return getEngineLootHelper('getDropEconomyValue')(path, fallback, { data: Data });
    }
    const parts = String(path || '').split('.').filter(Boolean);
    let value = Data.DROP_ECONOMY || {};
    for (const part of parts) {
      if (!value || typeof value !== 'object' || !Object.prototype.hasOwnProperty.call(value, part)) return fallback;
      value = value[part];
    }
    return value == null ? fallback : value;
  }

  function getDropEconomyNumber(path, fallback) {
    if (getEngineLootHelper('getDropEconomyNumber')) {
      return getEngineLootHelper('getDropEconomyNumber')(path, fallback, { data: Data });
    }
    const value = Number(getDropEconomyValue(path, fallback));
    return Number.isFinite(value) ? value : fallback;
  }

  const GET_OBJECTIVE_KEY = getEngineProgressObjectiveHelper('getObjectiveKey');
