  const CREATE_PROGRESS_STATE = getEngineProgressObjectiveHelper('createProgressState');
  const CREATE_MAP_KILL_QUEST_STATE = getEngineProgressObjectiveHelper('createMapKillQuestState');
  const CREATE_QUEST_GUIDE_STATE = getEngineProgressObjectiveHelper('createQuestGuideState');
  const ENSURE_PROGRESS_ENTRY = getEngineProgressObjectiveHelper('ensureProgressEntry');
  const OBJECTIVE_MATCHES_EVENT = getEngineProgressObjectiveHelper('objectiveMatchesEvent');
  const ADD_OBJECTIVE_TYPES = getEngineProgressObjectiveHelper('addObjectiveTypes');
  const CREATE_PROGRESS_OBJECTIVE_TYPE_SET = getEngineProgressObjectiveHelper('createProgressObjectiveTypeSet');
  const CREATE_OBJECTIVE_TYPE_ENTRY_MAP = getEngineProgressObjectiveHelper('createObjectiveTypeEntryMap');
  const GET_OBJECTIVE_TYPE_ENTRIES = getEngineProgressObjectiveHelper('getObjectiveTypeEntries');
  const CREATE_EVENT_STEP_MAP = getEngineProgressObjectiveHelper('createEventStepMap');
  const GET_EVENT_STEPS_BY_TYPE = getEngineProgressObjectiveHelper('getEventStepsByType');
  const CREATE_OBJECTIVE_STATUSES = getEngineProgressObjectiveHelper('createObjectiveStatuses');
  const APPLY_PROGRESS_EVENT_TO_ENTRY = getEngineProgressObjectiveHelper('applyProgressEventToEntry');

  function getObjectiveKey(objective, index) {
    if (GET_OBJECTIVE_KEY) {
      return GET_OBJECTIVE_KEY(objective, index);
    }
    return normalizeId(objective && objective.id) || `${normalizeId(objective && objective.type) || 'objective'}_${index}`;
  }

  function getObjectiveGoal(objective) {
    if (GET_OBJECTIVE_GOAL) {
      return GET_OBJECTIVE_GOAL(objective);
    }
    if (!objective) return 1;
    if (objective.type === 'level') return Math.max(1, Number(objective.level || objective.count || 1));
    return Math.max(1, Number(objective.count || 1));
  }

  function createProgressEntry(value) {
    if (CREATE_PROGRESS_ENTRY) {
      return CREATE_PROGRESS_ENTRY(value);
    }
    const source = value && typeof value === 'object' ? value : {};
    const objectiveValues = source.objectiveValues && typeof source.objectiveValues === 'object' ? source.objectiveValues : {};
    return {
      objectiveValues: Object.keys(objectiveValues).reduce((values, key) => {
        values[key] = Math.max(0, Number(objectiveValues[key]) || 0);
        return values;
      }, {}),
      completedAt: Number(source.completedAt || 0)
    };
  }

  const CREATE_TRIAL_INSTANCE_STATE = getEngineClassTrialHelper('createTrialInstanceState');
  const GET_ACTIVE_CLASS_TRIAL = getEngineClassTrialHelper('getActiveClassTrial');
  const IS_CLASS_TRIAL_COMPLETE = getEngineClassTrialHelper('isClassTrialComplete');
  const IS_TRIAL_INSTANCE_ACTIVE = getEngineClassTrialHelper('isTrialInstanceActive');
  const CREATE_TRIAL_INSTANCE_SNAPSHOT = getEngineClassTrialHelper('createTrialInstanceSnapshot');
  const GET_DEFAULT_CLASS_TRIAL_FOR_PLAYER = getEngineClassTrialHelper('getDefaultClassTrialForPlayer');
  function createTrialInstanceState(value) {
    if (CREATE_TRIAL_INSTANCE_STATE) {
      return CREATE_TRIAL_INSTANCE_STATE(value);
    }
    const source = value && typeof value === 'object' ? value : {};
    const trialId = normalizeId(source.trialId);
    return {
      active: !!source.active && !!trialId,
      trialId,
      returnMapId: normalizeId(source.returnMapId) || 'starfallCrossing',
      returnX: Number.isFinite(Number(source.returnX)) ? Number(source.returnX) : 1845,
      returnY: Number.isFinite(Number(source.returnY)) ? Number(source.returnY) : 360,
      startedAt: Number(source.startedAt || 0)
    };
  }

  function createProgressState(value) {
    if (CREATE_PROGRESS_STATE) {
      return CREATE_PROGRESS_STATE(value, { createTrialInstanceState });
    }
    const source = value && typeof value === 'object' ? value : {};
    const questProgress = {};
    Object.entries(source.questProgress || {}).forEach(([id, entry]) => {
      questProgress[id] = createProgressEntry(entry);
    });
    const trialProgress = {};
    Object.entries(source.trialProgress || {}).forEach(([id, entry]) => {
      trialProgress[id] = createProgressEntry(entry);
    });
    const completedTrials = {};
    Object.entries(source.completedTrials || {}).forEach(([id, done]) => {
      if (done) completedTrials[id] = true;
    });
    const completedQuestIds = Array.isArray(source.completedQuestIds)
      ? source.completedQuestIds.map(normalizeId).filter(Boolean)
      : [];
    const claimedQuestIds = Array.isArray(source.claimedQuestIds)
      ? source.claimedQuestIds.map(normalizeId).filter(Boolean)
      : completedQuestIds;
    return {
      activeQuestId: normalizeId(source.activeQuestId),
      completedQuestIds: Array.from(new Set(completedQuestIds)),
      claimedQuestIds: Array.from(new Set(claimedQuestIds)),
      questProgress,
      activeTrialId: normalizeId(source.activeTrialId),
      trialProgress,
      completedTrials,
      trialInstance: createTrialInstanceState(source.trialInstance)
    };
  }

