  function getEquippedStatBreakdown(state) {
    const gear = createEmptyEquipmentStats();
    const attunement = createEmptyEquipmentStats();
    const set = createEmptyEquipmentStats();
    Object.values(state.equipment || {}).forEach((item) => {
      if (!item) return;
      const upgradeMultiplier = 1 + Number(item.upgrade || 0) * 0.08;
      Object.entries(item.stats || {}).forEach(([key, value]) => {
        gear[key] = (gear[key] || 0) + Math.round(Number(value || 0) * upgradeMultiplier);
      });
      const trait = getGearTraitDefinition(item.traitId);
      if (trait && trait.statBonuses) addStats(gear, trait.statBonuses);
      addStats(attunement, getItemPotentialStats(item));
    });
    addStats(set, getEquippedSetBonuses(state));
    return { gear, attunement, set };
  }

