          const maxHpFlat = base.hp + gear.hp + Number(cards.hp || 0) + Number(roster.hp || 0) + Number(party.hp || 0) + Number(specialization.hp || 0) + Number(statUpgrades.hp || 0) + Number(permanent.hp || 0) + Number(passive.hp || 0) + levelBonus * 10;
          const maxHpPercent = sumStatFromSources('maxHpPercent', statSources);
